INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('land-agent-moex-00166', 'land-agent', 'land-agent-moex-106-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '「思考能力需要長期訓練，透過思考，可以幫助我們對於周遭事物作理性的分析、 準確的判斷。有時候，我雖然會刻意不去思考來放鬆自己，讓自己的思緒處於休息放空 的狀態，但人不太可能一直存在於不思考的狀態，這會讓你的反應越來越遲緩，腦袋也 會越來越遲鈍。 我們常常在看電視、上網的時候被動地接收了大量的資訊，讓我們的腦袋來不及思 考，而且這些資訊可能是跟我們毫不相干的事物，當這種情況持續下去，漸漸地，頭腦 反應也會越來越遲鈍。很多人覺得思考就像算數學一樣，令人頭痛。其實思考並不是一 件痛苦的事情，懂得思考的人會在生活中找到許多樂趣，這個樂趣來自於精準判斷一件 事物所帶來的成就感。」 根據本文的敘述，下列選項何者正確？', '["思考就像運算數學一樣，需要長時間的訓練，是一件痛苦的事情", "當我們能運用思考能力，準確地判斷事物時，會帶來一定的成就感", "常常放任自己生活在不思考的放鬆狀態，有助於沉澱心思使思考更縝密", "收看電視、瀏覽網頁，被動接收大量資訊，有助於我們思考能力的提昇"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "3877222b8d69", "answer_pdf_sha1": "09d2a498e185", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00167', 'land-agent', 'land-agent-moex-106-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '閱讀下文，選出最合乎作者意旨的選項： 「什麼是世間最苦的事？ 父母那一代：生離死別、戰亂、監禁、颱風天要拿著磚頭爬上去壓屋頂。 兄姊那一代：交不出郊遊費、買不起故事書、籌不到出國留學的旅費。 Ｘ世代：昨天一個朋友告訴我說，他一輩子最苦的一件事，就是在啤酒屋喝醉了， 走在路上吐了一地，並毫無知覺地躺在自己吐出的穢物上睡到天亮。醒來後的感覺是： 酷斃了。」', '["作者認為每一代的人們皆有他們所認為最艱苦的事，但其實一點也不苦", "作者條列出不同世代各自的艱辛，以表示世間苦事越來越多且更加瑣碎", "作者認為兄姊那一代的艱苦才真的是人世之苦辛，因為得為發展而搏鬥", "作者認為世間最苦的事，莫過於人們對生活目標生命意義的迷惘與喪失"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "3877222b8d69", "answer_pdf_sha1": "09d2a498e185", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00168', 'land-agent', 'land-agent-moex-106-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '《蘇軾文集．書戴嵩畫牛》：「蜀中有杜處士，好書畫，所寶以百數。有戴嵩〈牛〉一 軸，尤所愛，錦囊玉軸，常以自隨。一日曝書畫，有一牧童見之，拊掌大笑。曰：『此 畫鬭牛也。牛鬭，力在角，尾搐入兩股間。今乃掉尾而鬭，謬矣！』處士笑而然之。」 下列敘述最正確的是：', '["戴嵩畫牛可謂閉門造車", "蘇軾善繪畫故能辨瑕疵", "杜處士愛水牛勝過鬭牛", "牧童弄巧成拙貽笑大方"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "3877222b8d69", "answer_pdf_sha1": "09d2a498e185", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00169', 'land-agent', 'land-agent-moex-106-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '「每個人都需要一個黑暗房間，因為只有在那裡面，我們才看得見對我們來說真正重要 的東西。對大部分人來說，白天時，我們的內心世界是黑暗的。在朝九晚五的壓力中， 我們盲目地追趕著自己的行程。一個一個會議、一個一個deadline、回不完的E-mail、聽 不完的留言。在處理這些事情時，我們擰乾了大腦，卻很少碰觸到心。忠心耿耿地服膺 PDA，卻忘了人生的指令。我們不是在過『一個』獨一無二、永不再來的『人生』。而 是在過『很多個』不斷重複、平凡無奇的『一天』。『你最近好嗎？』朋友問。我們的 回答總是：『還好啊』、『差不多』、『就這樣』、『不錯啊那你呢？』我們迫不及待 地把問題丟回去。因為每當想起『最近』，我們想起的不是色彩鮮明的每一天，而是灰 暗混沌的一大片。」上文旨在說明：', '["都市人的冷漠", "現代生活的繁忙", "現代人需要寂靜隔絕的空間", "現代人需要思考人生的意義"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "3877222b8d69", "answer_pdf_sha1": "09d2a498e185", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00170', 'land-agent', 'land-agent-moex-106-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '就旅遊言，一旦站在千丘萬壑的大峽谷前感到自己渺如蟻螻，還有什麼時候你能如此心 甘情願地卑微下來，享受大化的赫赫天威？又嘗記得一次夏夜，臥在沙灘上看滿天繁星 如雨陣如箭鏃，一時幾乎驚得昏呆過去，有一種投身在偉大之下的絕望，知道人類永永 遠遠不能去逼近那百萬光年之外的光體，這份絕望使我一想起來仍覺興奮昂揚。 下列何者最接近此段的文意？', '["對大自然的禮讚", "對往日時光的懷念", "對生命起源的探索", "讀萬卷書也要行千里路 閱讀下文，回答第19題至第20題 在這份「地球十二月分大年曆」中，1月1日地球誕生了。 請記住，這個年曆，一天代表一千二百五十萬年。 讓我們看月曆圖下的那行字："]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "3877222b8d69", "answer_pdf_sha1": "09d2a498e185", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00171', 'land-agent', 'land-agent-moex-106-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '月 1 日，地球出現最初的生命，也就是細菌。8 月 15 日，第一個多細胞生物出現。11 月，脊椎動物出現。 12月1日，陸地動物出現。12月13日，最早的恐龍出現。12月14日，哺乳類出現。 12月15-25日，恐龍的活躍期；這前後十一天，換算成「年」，是一億數千萬年。', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "3877222b8d69", "answer_pdf_sha1": "09d2a498e185", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00172', 'land-agent', 'land-agent-moex-106-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '月 26 日，恐龍滅絕；靈長類動物出現。12 月 29 日，喜馬拉雅造山運動開始。 12月30日，猿類出現。在這一整年的最後一天的正午，人類和黑猩猩分化。人類和黑猩 猩分途發展到我們真正的祖先「現代人」出現，已經是這一整年的最後一天晚間11點40 分之後的事，也就是倒數第二十分鐘了！ 倒數最後一分三十秒，冰河時期結束，人類抵達美洲。倒數最後一分鐘，人類開始馴化 動物，農耕出現。 倒數最後一秒，也就是距今一百五十年內，你、我，以及你的父母和祖父母，統統活在 這一秒內！ 地球的歷史這麼久遠，人類的出現又是這麼晚、這麼近。在每年的最後一秒中，當人們 興奮地等待煙火或爆竹時，讓我們思考這個問題，以及我們對地球的責任。', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "3877222b8d69", "answer_pdf_sha1": "09d2a498e185", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00173', 'land-agent', 'land-agent-moex-106-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '以下那一選項是作者藉由「地球十二月分大年曆」所欲揭櫫的文旨？', '["標示地球每個不同階段的生物期", "結合歷史與生物科學，促進人類文明發展", "相較於地球歷史的久遠，人類的出現，是如此之晚", "藉由科學數字，精準記錄人類與地球的歷史，以供科學家引據"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "3877222b8d69", "answer_pdf_sha1": "09d2a498e185", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00174', 'land-agent', 'land-agent-moex-106-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '「你、我，以及你的父母和祖父母，統統活在這一秒內！」下列那一選項可以呼應此文 旨趣？', '["水之積也不厚，則其負大舟也無力", "古之至人，先存諸己，而後存諸人", "道惡乎隱而有真偽，言惡乎隱而有是非", "小知不及大知，小年不及大年；朝菌不知晦朔，蟪蛄不知春秋"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "3877222b8d69", "answer_pdf_sha1": "09d2a498e185", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00175', 'land-agent', 'land-agent-moex-106-8c177526', 'sub-land-agent-01', NULL, 'essay', '某甲為台裔美國人，不具我國國籍，其父某乙所有位於某縣非都市山坡地保育區一
